mapper.select:
SELECT balance_id, employee_no, year,
       total_days, used_days, carry_over, remaining, updated_at
FROM platform_v3.at_leave_balance
WHERE employee_no = #{employeeNo}
  AND year        = #{year}

mapper.update:
UPDATE platform_v3.at_leave_balance
   SET used_days  = used_days + #{addDays},
       updated_at = NOW()
 WHERE employee_no = #{employeeNo}
   AND year        = #{year}

UPDATE platform_v3.at_leave_request
   SET status = #{status}
 WHERE request_id = #{requestId}
